import React, { useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../auth/AuthContext';
import FlashBar from '../components/FlashBar';

const initialRegister = {
  email: '',
  phone: '',
  username: '',
  password: '',
  role: 'DONOR',
};

const initialLogin = {
  email: '',
  password: '',
};

const demoCredentials = {
  admin: {
    label: 'Network Command',
    email: 'admin@blooddonation.com',
    password: 'SecurePass@123',
  },
  donor: {
    label: 'Fulfilling Hospital',
    email: 'donor@blooddonation.com',
    password: 'SecurePass@123',
  },
  recipient: {
    label: 'Requesting Hospital',
    email: 'recipient@blooddonation.com',
    password: 'SecurePass@123',
  },
};

const workflowSteps = [
  {
    stage: '01',
    title: 'Requesting Hospital Raises Need',
    text: 'A hospital case desk submits a blood or organ requirement with clinical notes, urgency, and due time.',
  },
  {
    stage: '02',
    title: 'Central Desk Reviews And Broadcasts',
    text: 'The command center validates the case, pushes alerts, and activates the matching workflow across the network.',
  },
  {
    stage: '03',
    title: 'Fulfilling Hospital Confirms Supply',
    text: 'Compatible hospital donor teams review requests, accept workable cases, and coordinate the fulfillment path.',
  },
  {
    stage: '04',
    title: 'Inter-Hospital Handover Happens',
    text: 'Appointments, approvals, contact points, and audit updates stay visible until the requirement is fulfilled.',
  },
];

const roleCards = [
  {
    role: 'RECIPIENT',
    eyebrow: 'Requesting Hospital',
    title: 'Raise a real case, not just a generic request',
    text: 'Use this role for the hospital that needs blood or an organ support path for a patient.',
  },
  {
    role: 'DONOR',
    eyebrow: 'Fulfilling Hospital',
    title: 'Respond as the hospital that can supply',
    text: 'Use this role for the hospital coordination team that can fulfill compatible requests from the network.',
  },
  {
    role: 'ADMIN',
    eyebrow: 'Central Command',
    title: 'Control review, routing, and approvals',
    text: 'Use this role for the network operations desk overseeing governance and inter-hospital coordination.',
  },
];

const roleLabels = {
  DONOR: 'Fulfilling Hospital',
  RECIPIENT: 'Requesting Hospital',
  ADMIN: 'Central Command',
};

function AuthPage() {
  const navigate = useNavigate();
  const { login, register, flash, setFlash } = useAuth();

  const [mode, setMode] = useState('login');
  const [registerForm, setRegisterForm] = useState(initialRegister);
  const [loginForm, setLoginForm] = useState(initialLogin);
  const [busy, setBusy] = useState(false);

  const selectedRoleCard = useMemo(
    () => roleCards.find((item) => item.role === registerForm.role) || roleCards[1],
    [registerForm.role]
  );

  function applyDemo(type) {
    const creds = demoCredentials[type];
    if (!creds) return;

    setMode('login');
    setLoginForm({
      email: creds.email,
      password: creds.password,
    });
  }

  async function handleRegister(event) {
    event.preventDefault();
    setBusy(true);
    try {
      await register(registerForm);
      navigate('/verify');
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    } finally {
      setBusy(false);
    }
  }

  async function handleLogin(event) {
    event.preventDefault();
    setBusy(true);
    try {
      const data = await login(loginForm);
      const userRole = data?.user?.role;

      if (userRole === 'DONOR') {
        navigate('/donor/medical-profile');
      } else if (userRole === 'ADMIN') {
        navigate('/admin/recipient-requests');
      } else if (userRole === 'RECIPIENT') {
        navigate('/recipient/request');
      } else {
        navigate('/dashboard');
      }
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    } finally {
      setBusy(false);
    }
  }

  return (
    <div className="auth-shell">
      <div className="auth-wrap">
        <section className="panel auth-showcase">
          <div className="auth-showcase-top">
            <p className="eyebrow">Hospital Network Access</p>
            <h2>CareFlow Command Gateway</h2>
            <p className="auth-showcase-copy">
              A coordinated access point for requesting hospitals, fulfilling hospitals,
              and the central operations desk managing critical blood and organ workflows.
            </p>
          </div>

          <div className="auth-highlight-band">
            <div>
              <strong>Real workflow</strong>
              <span>Hospital-to-hospital fulfillment with visible approvals and case handover.</span>
            </div>
            <div>
              <strong>Shared command view</strong>
              <span>One system for review, routing, matching, and scheduling.</span>
            </div>
          </div>

          <div className="auth-role-grid">
            {roleCards.map((item) => (
              <article key={item.role} className="auth-role-card">
                <p>{item.eyebrow}</p>
                <h3>{item.title}</h3>
                <span>{item.text}</span>
              </article>
            ))}
          </div>

          <div className="auth-process-card">
            <div className="auth-process-head">
              <h3>Hospital Coordination Workflow</h3>
              <p>How a need moves across the network.</p>
            </div>
            <div className="auth-process-list">
              {workflowSteps.map((item) => (
                <article key={item.stage} className="auth-process-step">
                  <span>{item.stage}</span>
                  <div>
                    <strong>{item.title}</strong>
                    <p>{item.text}</p>
                  </div>
                </article>
              ))}
            </div>
          </div>

          <div className="auth-credential-card">
            <div className="auth-credential-head">
              <div>
                <h4>Demo Access</h4>
                <p>Use these roles to walk the full workflow end to end.</p>
              </div>
              <div className="auth-demo-actions">
                <button type="button" className="btn-ghost" onClick={() => applyDemo('recipient')}>Requesting Hospital</button>
                <button type="button" className="btn-ghost" onClick={() => applyDemo('donor')}>Fulfilling Hospital</button>
                <button type="button" className="btn-ghost" onClick={() => applyDemo('admin')}>Central Command</button>
              </div>
            </div>

            <div className="auth-demo-grid">
              {Object.values(demoCredentials).map((item) => (
                <div key={item.email} className="auth-demo-tile">
                  <strong>{item.label}</strong>
                  <span>{item.email}</span>
                  <span>{item.password}</span>
                </div>
              ))}
            </div>
          </div>
        </section>

        <section className="panel auth-card auth-form-card">
          <div className="auth-card-top">
            <div>
              <p className="eyebrow">Secure Portal Access</p>
              <h2>{mode === 'login' ? 'Continue your hospital workflow' : 'Create a hospital network account'}</h2>
              <p className="auth-subtext">
                {mode === 'login'
                  ? 'Sign in to continue request review, fulfillment coordination, and live case tracking.'
                  : 'Register your role first, then verify identity before entering the live coordination workflow.'}
              </p>
            </div>
            <div className="auth-security-note">
              <strong>Protected access</strong>
              <span>OTP verification, role isolation, and tracked operational actions.</span>
            </div>
          </div>

          <FlashBar flash={flash} />

          <div className="auth-switch">
            <button
              type="button"
              className={mode === 'login' ? 'active' : ''}
              onClick={() => setMode('login')}
            >
              Sign In
            </button>
            <button
              type="button"
              className={mode === 'register' ? 'active' : ''}
              onClick={() => setMode('register')}
            >
              Register
            </button>
          </div>

          {mode === 'login' ? (
            <form onSubmit={handleLogin} className="auth-form-grid">
              <label>
                Hospital Email
                <input
                  type="email"
                  placeholder="hospital.team@example.com"
                  value={loginForm.email}
                  onChange={(e) => setLoginForm((prev) => ({ ...prev, email: e.target.value }))}
                  required
                />
              </label>
              <label>
                Password
                <input
                  type="password"
                  placeholder="Enter your password"
                  value={loginForm.password}
                  onChange={(e) => setLoginForm((prev) => ({ ...prev, password: e.target.value }))}
                  required
                />
              </label>
              <button type="submit" className="btn-solid" disabled={busy}>
                {busy ? 'Authenticating...' : 'Enter Command Portal'}
              </button>
            </form>
          ) : (
            <>
              <div className="auth-role-preview">
                <p>{selectedRoleCard.eyebrow}</p>
                <strong>{selectedRoleCard.title}</strong>
                <span>{selectedRoleCard.text}</span>
              </div>

              <form onSubmit={handleRegister} className="auth-form-grid">
                <label>
                  Hospital Email
                  <input
                    type="email"
                    placeholder="hospital.team@example.com"
                    value={registerForm.email}
                    onChange={(e) => setRegisterForm((prev) => ({ ...prev, email: e.target.value }))}
                    required
                  />
                </label>
                <label>
                  Phone
                  <input
                    placeholder="+91xxxxxxxxxx"
                    value={registerForm.phone}
                    onChange={(e) => setRegisterForm((prev) => ({ ...prev, phone: e.target.value }))}
                    required
                  />
                </label>
                <label>
                  Username
                  <input
                    placeholder="Choose a username"
                    value={registerForm.username}
                    onChange={(e) => setRegisterForm((prev) => ({ ...prev, username: e.target.value }))}
                    required
                  />
                </label>
                <label>
                  Password
                  <input
                    type="password"
                    placeholder="Create a strong password"
                    value={registerForm.password}
                    onChange={(e) => setRegisterForm((prev) => ({ ...prev, password: e.target.value }))}
                    required
                  />
                </label>
                <label>
                  Role
                  <select
                    value={registerForm.role}
                    onChange={(e) => setRegisterForm((prev) => ({ ...prev, role: e.target.value }))}
                  >
                    <option value="DONOR">{roleLabels.DONOR}</option>
                    <option value="RECIPIENT">{roleLabels.RECIPIENT}</option>
                    <option value="ADMIN">{roleLabels.ADMIN}</option>
                  </select>
                </label>
                <button type="submit" className="btn-solid" disabled={busy}>
                  {busy ? 'Creating account...' : 'Register And Continue'}
                </button>
              </form>
            </>
          )}

          <div className="auth-footer-panel">
            <p>
              This portal is designed for real hospital routing: one team raises the case, another team can fulfill it,
              and central command keeps the whole exchange auditable.
            </p>
            <p className="auth-footer-link">
              Looking for platform details first? <Link to="/">Go to landing page</Link>
            </p>
          </div>
        </section>
      </div>
    </div>
  );
}

export default AuthPage;
